export const getBillType = (id) => BILL_TYPES.find((t) => t.id === id) || BILL_TYPES.find((t) => t.id === "other");

// Service categories in display order (matches SUBSCRIPTION_SERVICES categories).
export const SERVICE_CATEGORIES = [...new Set(SUBSCRIPTION_SERVICES.map((s) => s.category))];

// A small curated set shown inline before the All tile (one nice logo per common pick).
export const POPULAR_SERVICE_IDS = ["netflix","spotify","youtube","chatgpt","appletv","amazon","vodafone","disney"];
